1	// Skill usage tracker — AB-4.
2	//
3	// Maintains `skill-usage.json` inside ${MEMORY_DIR}/config/ so that
4	// usage counts are shared across all agent CLIs (Kiro / Claude / Codex).
5	// Previously stored as `.usage.json` inside ${SKILL_DIR}; on first run
6	// the old file is auto-migrated if the new one doesn't exist yet.
7	// Schema documented in docs/ab-token-protocol.md §6.1.
8	//
9	// Responsibilities:
10	//   • migrateFromDisk() — on first run (and occasionally thereafter),
11	//     scan ${SKILL_DIR}/*/SKILL.md, create entries for skills not yet
12	//     tracked, and flag entries whose SKILL.md has disappeared.
13	//   • markListed(name) — bump `last_bridge_listed_at`; used when
14	//     /skillusage displays the skill in bridge output.
15	//   • markUsed(name, reason) — called by observerTransformer when it
16	//     extracts a <<SKILL_USED:name|reason>> token. Updates
17	//     `last_agent_used_at`, `last_reason`, `use_count++`. Creates an
18	//     orphan entry if `name` has no SKILL.md on disk.
19	//   • setPinned(name, pinned) — flip the `pinned` flag.
20	//   • listAll() — read-only snapshot for the /skillusage handler.
21	//
22	// Concurrency: every mutation goes through atomicJson.updateJson(),
23	// which serializes read-modify-write per file path in-process. Single
24	// bridge process assumption — see atomicJson.ts §not-a-goal for the
25	// multi-process caveat.
26	
27	import { readdir, stat } from "node:fs/promises";
28	import path from "node:path";
29	import { existsSync } from "node:fs";
30	import {
31	  atomicWriteJson,
32	  readJsonOrDefault,
33	  updateJson,
34	} from "./atomicJson.js";
35	import { config } from "./config.js";
36	
37	/** Per-skill entry. Keep fields aligned with docs/ab-token-protocol.md §6.1. */
38	export interface UsageEntry {
39	  created_at: string;            // ISO, first time bridge saw this skill
40	  last_bridge_listed_at: string | null;
41	  last_agent_used_at: string | null;
42	  use_count: number;
43	  last_reason: string | null;
44	  pinned: boolean;
45	  notes: string | null;
46	  orphan: boolean;
47	}
48	
49	/** File contents. */
50	export interface UsageJson {
51	  _schema_version: 1;
52	  _last_updated_at: string | null;
53	  skills: Record<string, UsageEntry>;
54	}
55	
56	/** Factory for a blank schema. */
57	function emptyUsageJson(): UsageJson {
58	  return {
59	    _schema_version: 1,
60	    _last_updated_at: null,
61	    skills: {},
62	  };
63	}
64	
65	/** Factory for a fresh entry. created_at is caller-supplied so migration
66	 * can back-date using the SKILL.md mtime. */
67	function newEntry(createdAt: string, orphan = false): UsageEntry {
68	  return {
69	    created_at: createdAt,
70	    last_bridge_listed_at: null,
71	    last_agent_used_at: null,
72	    use_count: 0,
73	    last_reason: null,
74	    pinned: false,
75	    notes: null,
76	    orphan,
77	  };
78	}
79	
80	function nowIso(): string {
81	  return new Date().toISOString();
82	}
83	
84	/** Full path to the centralized usage file (MEMORY_DIR/config/skill-usage.json).
85	 * The skillDir param is kept for backward compat but ignored for path resolution. */
86	export function usageFilePath(_skillDir?: string): string {
87	  return path.join(config.memoryDir, "config", "skill-usage.json");
88	}
89	
90	/** Legacy path — old location inside SKILL_DIR. Used for one-time migration. */
91	function legacyUsageFilePath(skillDir: string): string {
92	  return path.join(skillDir, ".usage.json");
93	}
94	
95	/** One-time migration: if new location doesn't exist but old one does,
96	 * copy old → new. Merges if both exist (new wins on conflict). */
97	export async function migrateUsageFileIfNeeded(skillDir: string): Promise<boolean> {
98	  const newPath = usageFilePath();
99	  const oldPath = legacyUsageFilePath(skillDir);
100	  if (existsSync(newPath) || !existsSync(oldPath)) return false;
101	
102	  // Old exists, new doesn't — read old and write to new location
103	  const oldData = await readJsonOrDefault<UsageJson>(oldPath, emptyUsageJson);
104	  const { mkdirSync } = await import("node:fs");
105	  mkdirSync(path.dirname(newPath), { recursive: true });
106	  await atomicWriteJson(newPath, oldData);
107	  console.log(`[usageStore] Migrated .usage.json from ${oldPath} → ${newPath}`);
108	  return true;
109	}
110	
111	// ───────────────────────────────────────────────────────────────────────
112	// Disk scan — discover skills by reading SKILL_DIR
113	// ───────────────────────────────────────────────────────────────────────
114	
115	/** A skill lives at `${SKILL_DIR}/<name>/SKILL.md`. Return the list of
116	 * names and their SKILL.md mtimes, sorted by name. Hidden dirs (dot-
117	 * prefix, `.archive/`, etc.) are skipped. Missing SKILL_DIR → []. */
118	export async function scanSkillDir(
119	  skillDir: string,
120	): Promise<Array<{ name: string; mtime: Date }>> {
121	  let entries: string[];
122	  try {
123	    entries = await readdir(skillDir);
124	  } catch (err: any) {
125	    if (err?.code === "ENOENT") return [];
126	    throw err;
127	  }
128	  const found: Array<{ name: string; mtime: Date }> = [];
129	  for (const e of entries) {
130	    if (e.startsWith(".")) continue;
131	    const skillMdPath = path.join(skillDir, e, "SKILL.md");
132	    try {
133	      const st = await stat(skillMdPath);
134	      if (st.isFile()) {
135	        found.push({ name: e, mtime: st.mtime });
136	      }
137	    } catch {
138	      // No SKILL.md in this dir — not a skill, skip silently.
139	    }
140	  }
141	  found.sort((a, b) => a.name.localeCompare(b.name));
142	  return found;
143	}
144	
145	// ───────────────────────────────────────────────────────────────────────
146	// CRUD
147	// ───────────────────────────────────────────────────────────────────────
148	
149	/** Read-only snapshot. Returns the full UsageJson, creating an empty one
150	 * if the file doesn't exist (without writing). */
151	export async function listAll(skillDir: string): Promise<UsageJson> {
152	  return readJsonOrDefault<UsageJson>(
153	    usageFilePath(),
154	    emptyUsageJson,
155	  );
156	}
157	
158	/** Ensure each skill on disk has an entry, and mark any entry whose
159	 * SKILL.md has disappeared as `orphan: true`. Does NOT remove orphan
160	 * entries — that's a user-driven decision (the /skillusage output
161	 * flags them so the user can `/pin` or clean up manually).
162	 *
163	 * Returns a summary for logging: added names, newly-orphaned names,
164	 * de-orphaned names (SKILL.md reappeared). */
165	export async function migrateFromDisk(
166	  skillDir: string,
167	): Promise<{
168	  added: string[];
169	  newlyOrphaned: string[];
170	  deOrphaned: string[];
171	}> {
172	  // One-time migration from old SKILL_DIR/.usage.json to MEMORY_DIR/config/
173	  await migrateUsageFileIfNeeded(skillDir);
174	
175	  const diskList = await scanSkillDir(skillDir);
176	  const diskByName = new Map<string, Date>();
177	  for (const s of diskList) diskByName.set(s.name, s.mtime);
178	
179	  const added: string[] = [];
180	  const newlyOrphaned: string[] = [];
181	  const deOrphaned: string[] = [];
182	
183	  await updateJson<UsageJson>(
184	    usageFilePath(),
185	    emptyUsageJson,
186	    (current) => {
187	      const next: UsageJson = {
188	        ...current,
189	        _last_updated_at: nowIso(),
190	        skills: { ...current.skills },
191	      };
192	      // Add entries for new skills
193	      for (const { name, mtime } of diskList) {
194	        if (!(name in next.skills)) {
195	          next.skills[name] = newEntry(mtime.toISOString(), false);
196	          added.push(name);
197	        } else if (next.skills[name].orphan) {
198	          next.skills[name] = { ...next.skills[name], orphan: false };
199	          deOrphaned.push(name);
200	        }
201	      }
202	      // Flag entries whose SKILL.md no longer exists.
203	      for (const name of Object.keys(next.skills)) {
204	        if (!diskByName.has(name) && !next.skills[name].orphan) {
205	          next.skills[name] = { ...next.skills[name], orphan: true };
206	          newlyOrphaned.push(name);
207	        }
208	      }
209	      return next;
210	    },
211	  );
212	
213	  return { added, newlyOrphaned, deOrphaned };
214	}
