216	/** Record that the bridge listed this skill to the user (e.g. via
217	 * /skillusage). Creates an orphan entry if `name` isn't on disk. */
218	export async function markListed(
219	  skillDir: string,
220	  name: string,
221	): Promise<void> {
222	  const ts = nowIso();
223	  await updateJson<UsageJson>(
224	    usageFilePath(),
225	    emptyUsageJson,
226	    (current) => {
227	      const next: UsageJson = {
228	        ...current,
229	        _last_updated_at: ts,
230	        skills: { ...current.skills },
231	      };
232	      const existing = next.skills[name];
233	      if (existing) {
234	        next.skills[name] = { ...existing, last_bridge_listed_at: ts };
235	      } else {
236	        next.skills[name] = {
237	          ...newEntry(ts, /* orphan */ true),
238	          last_bridge_listed_at: ts,
239	        };
240	      }
241	      return next;
242	    },
243	  );
244	}
