246	/** Record that the agent used this skill (from a <<SKILL_USED>> token).
247	 * Creates an orphan entry if `name` isn't on disk. */
248	export async function markUsed(
249	  skillDir: string,
250	  name: string,
251	  reason: string,
252	): Promise<void> {
253	  const ts = nowIso();
254	  // Detect orphan at write time. We do one `stat` per call — cheap and
255	  // avoids stale in-memory caches disagreeing with disk.
256	  let diskExists = false;
257	  try {
258	    const st = await stat(path.join(skillDir, name, "SKILL.md"));
259	    diskExists = st.isFile();
260	  } catch {
261	    diskExists = false;
262	  }
263	
264	  await updateJson<UsageJson>(
265	    usageFilePath(),
266	    emptyUsageJson,
267	    (current) => {
268	      const next: UsageJson = {
269	        ...current,
270	        _last_updated_at: ts,
271	        skills: { ...current.skills },
272	      };
273	      const existing = next.skills[name];
274	      if (existing) {
275	        next.skills[name] = {
276	          ...existing,
277	          last_agent_used_at: ts,
278	          last_reason: reason,
279	          use_count: existing.use_count + 1,
280	          // Transition in/out of orphan state based on current disk.
281	          orphan: !diskExists,
282	        };
283	      } else {
284	        next.skills[name] = {
285	          ...newEntry(ts, !diskExists),
286	          last_agent_used_at: ts,
287	          last_reason: reason,
288	          use_count: 1,
289	        };
290	      }
291	      return next;
292	    },
293	  );
294	}
295	
296	/** Flip the pinned flag for an existing entry. If the name has no entry
297	 * yet (never listed, never used), we create a stub so the flag persists. */
298	export async function setPinned(
299	  skillDir: string,
300	  name: string,
301	  pinned: boolean,
302	): Promise<void> {
303	  const ts = nowIso();
304	  await updateJson<UsageJson>(
305	    usageFilePath(),
306	    emptyUsageJson,
307	    (current) => {
308	      const next: UsageJson = {
309	        ...current,
310	        _last_updated_at: ts,
311	        skills: { ...current.skills },
312	      };
313	      const existing = next.skills[name];
314	      if (existing) {
315	        next.skills[name] = { ...existing, pinned };
316	      } else {
317	        next.skills[name] = { ...newEntry(ts, /* orphan */ true), pinned };
318	      }
319	      return next;
320	    },
321	  );
322	}
323	
324	/** Convenience: does this skill have `pinned: true`? Returns false if
325	 * no entry exists yet. */
326	export async function isPinned(
327	  skillDir: string,
328	  name: string,
329	): Promise<boolean> {
330	  const all = await listAll(skillDir);
331	  return all.skills[name]?.pinned === true;
332	}
